import React from 'react';
import { Linking, NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

function ProfileScreen({ route }) {
  const { userId } = route.params;
  return <Text>Profile of user {userId}</Text>;
}

function PaymentConfirmScreen() {
  return <Text>Payment Confirmation</Text>;
}

function App() {
  React.useEffect(() => {
    Linking.addEventListener('url', handleDeepLink);
    return () => Linking.removeEventListener('url', handleDeepLink);
  }, []);

  const handleDeepLink = (event) => {
    if (event.url.includes('/profile/')) {
      const userId = event.url.split('/')[2];
      navigation.navigate('Profile', { userId });
    } else if (event.url === 'myapp://payment/confirm') {
      navigation.navigate('PaymentConfirm');
    }
  };

  return (
    <NavigationContainer>
      <Stack.Navigator initialRouteName="Home">
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

export default App;